import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible, jiraData }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title">Imported Jira User Stories</div>

      {loading && <div>Loading...</div>}
      {error && <div className="error">{error}</div>}

      <div className="jira-stories">
        {jiraData.length === 0 && !loading ? (
          <div>No Jira stories found.</div>
        ) : (
          jiraData.map((story) => (
            <div
              key={story.key}
              className="jira-story-box"
              onClick={() => onSelectUserStory(story)} // Pass the full story object
            >
              <strong>{story.summary}</strong>
              <div>Key: {story.key}</div>
              <div>Reporter: {story.reporter}</div>
              <div>Description: {story.description}</div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
